  1→// lib/serval-proxy/forwarder.zig
  2→//! Upstream Forwarder
  3→//!
  4→//! Forwards HTTP/1.1 requests to upstream servers with connection pooling.
  5→//! TigerStyle: Zero-copy where possible, bounded loops, ~2 assertions per function.
  6→
  7→const std = @import("std");
  8→const assert = std.debug.assert;
  9→const Io = std.Io;
 10→
 11→const serval_core = @import("serval-core");
 12→const config = serval_core.config;
 13→const types = serval_core.types;
 14→const debugLog = serval_core.debugLog;
 15→const time = serval_core.time;
 16→const SpanHandle = serval_core.SpanHandle;
 17→
 18→const serval_tracing = @import("serval-tracing");
 19→const verifyTracer = serval_tracing.verifyTracer;
 20→
 21→const pool_mod = @import("serval-pool").pool;
 22→
 23→const proxy_types = @import("types.zig");
 24→pub const ForwardError = proxy_types.ForwardError;
 25→pub const ForwardResult = proxy_types.ForwardResult;
 26→pub const BodyInfo = proxy_types.BodyInfo;
 27→const Protocol = proxy_types.Protocol;
 28→
 29→const connect = @import("connect.zig");
 30→const ConnectResult = connect.ConnectResult;
 31→const ConnectConfig = connect.ConnectConfig;
 32→const connectUpstream = connect.connectUpstream;
 33→const getLocalPortFromSocket = connect.getLocalPortFromSocket;
 34→
 35→const h1 = @import("h1/mod.zig");
 36→const sendRequest = h1.sendRequest;
 37→const sendUpgradeRequest = h1.sendUpgradeRequest;
 38→const ForwardedHeaders = h1.ForwardedHeaders;
 39→const methodToString = h1.methodToString;
 40→const streamRequestBody = h1.streamRequestBody;
 41→const forwardResponse = h1.forwardResponse;
 42→const forwardUpgradeResponse = h1.forwardUpgradeResponse;
 43→
 44→const tunnel_mod = @import("tunnel.zig");
 45→
 46→const serval_websocket = @import("serval-websocket");
 47→const serval_h2 = @import("serval-h2");
 48→const serval_grpc = @import("serval-grpc");
 49→
 50→const serval_tls = @import("serval-tls");
 51→const TLSStream = serval_tls.TLSStream;
 52→const ssl = serval_tls.ssl;
 53→
 54→const serval_net = @import("serval-net");
 55→const DnsResolver = serval_net.DnsResolver;
 56→const DnsConfig = serval_net.DnsConfig;
 57→
 58→const serval_socket = @import("serval-socket");
 59→const Socket = serval_socket.Socket;
 60→
 61→const Request = types.Request;
 62→const Upstream = types.Upstream;
 63→const Method = types.Method;
 64→const Connection = pool_mod.Connection;
 65→
 66→// =============================================================================
 67→// Forwarder
 68→// =============================================================================
 69→
 70→pub fn Forwarder(comptime Pool: type, comptime Tracer: type) type {
 71→    pool_mod.verifyPool(Pool);
 72→    verifyTracer(Tracer);
 73→
 74→    return struct {
 75→        const Self = @This();
 76→
 77→        pool: *Pool,
 78→        tracer: *Tracer,
 79→        verify_upstream_tls: bool,
 80→        /// Optional SSL context for upstream TLS connections.
 81→        /// Caller provides and owns lifecycle; null means no TLS to upstreams.
 82→        /// TigerStyle: Explicit ownership, caller manages context.
 83→        client_ctx: ?*ssl.SSL_CTX,
 84→        /// DNS resolver with TTL caching for hostname resolution.
 85→        /// TigerStyle: Fixed-size cache, thread-safe, no runtime allocation.
 86→        dns_resolver: DnsResolver,
 87→
 88→        pub fn init(
 89→            p: *Pool,
 90→            t: *Tracer,
 91→            verify_upstream_tls: bool,
 92→            client_ctx: ?*ssl.SSL_CTX,
 93→            dns_config: DnsConfig,
 94→        ) Self {
 95→            // S1: preconditions - pointers must be valid
 96→            assert(@intFromPtr(p) != 0);
 97→            assert(@intFromPtr(t) != 0);
 98→
 99→            var dns_resolver: DnsResolver = undefined;
100→            DnsResolver.init(&dns_resolver, dns_config);
101→
102→            return .{
103→                .pool = p,
104→                .tracer = t,
105→                .verify_upstream_tls = verify_upstream_tls,
106→                .client_ctx = client_ctx,
107→                .dns_resolver = dns_resolver,
108→            };
109→        }
110→
111→        /// Maximum stale connection retries - imported from config.
112→        /// TigerStyle: Single source of truth for tunables.
113→        const MAX_STALE_RETRIES = config.MAX_STALE_RETRIES;
114→
115→        /// Forward request to upstream, returning response metadata.
116→        /// Auto-retries up to MAX_STALE_RETRIES on stale pooled connections.
117→        /// body_info contains metadata for streaming request body from client.
118→        /// parent_span is the root request span for creating child trace spans.
119→        /// client_tls is the TLS stream for client connection (for encrypted responses).
120→        /// effective_path: If set, use this path instead of request.path (for path rewriting).
121→        /// TigerStyle: Takes client stream for async I/O, bounded retries.
122→        pub fn forward(
123→            self: *Self,
124→            io: Io,
125→            client_stream: Io.net.Stream,
126→            client_tls: ?*TLSStream,
127→            request: *const Request,
128→            upstream: *const Upstream,
129→            body_info: BodyInfo,
130→            parent_span: SpanHandle,
131→            effective_path: ?[]const u8,
132→        ) ForwardError!ForwardResult {
133→            assert(upstream.port > 0);
134→            // S1: precondition - path must not be empty (use effective_path if provided)
135→            const path = effective_path orelse request.path;
136→            assert(path.len > 0);
137→
138→            // Create forward span as child of request span
139→            const forward_span = self.tracer.startSpan("forward_to_upstream", parent_span);
140→            errdefer self.tracer.endSpan(forward_span, "forward_error");
141→
142→            debugLog("forward: start {s} {s} upstream={s}:{d}", .{
143→                methodToString(request.method),
144→                path,
145→                upstream.host,
146→                upstream.port,
147→            });
148→
149→            // Pool acquire phase with span
150→            // TigerStyle: End span only after we know if connection actually worked,
151→            // not immediately after acquire. Tracks stale_retries for observability.
152→            const pool_span = self.tracer.startSpan("pool_acquire", forward_span);
153→            const pool_start_ns = time.monotonicNanos();
154→            var stale_retries: u8 = 0;
155→
156→            // Try pooled connections with bounded retry on stale
157→            while (stale_retries < MAX_STALE_RETRIES) : (stale_retries += 1) {
158→                if (self.pool.acquire(upstream.idx)) |pooled_conn| {
159→                    const pool_end_ns = time.monotonicNanos();
160→                    const pool_wait_ns = time.elapsedNanos(pool_start_ns, pool_end_ns);
161→
162→                    // Check for unusable connection before using pooled connection
163→                    // TigerStyle: Detect stale data, closed by peer, socket errors.
164→                    if (pooled_conn.isUnusable()) {
165→                        debugLog("forward: pool hit but STALE (retry {d}/{d}), closing", .{ stale_retries + 1, MAX_STALE_RETRIES });
166→                        var stale_conn = pooled_conn;
167→                        stale_conn.close();
168→                        continue; // Try next pooled connection
169→                    }
170→
171→                    // DON'T end span here - wait until we know connection works
172→                    debugLog("forward: pool HIT, reusing connection fd={d}", .{pooled_conn.socket.get_fd()});
173→
174→                    // Get local port from pooled connection
175→                    const local_port = getLocalPortFromSocket(pooled_conn.socket);
176→
177→                    const result = self.forwardWithConnection(
178→                        io,
179→                        client_stream,
180→                        client_tls,
181→                        request,
182→                        upstream,
183→                        pooled_conn,
184→                        true,
185→                        body_info,
186→                        0, // dns_duration_ns: 0 for pooled connection
187→                        0, // tcp_connect_duration_ns: 0 for pooled connection
188→                        local_port,
189→                        pool_wait_ns,
190→                        forward_span,
191→                        effective_path,
192→                    ) catch |err| {
193→                        if (err == ForwardError.StaleConnection and stale_retries + 1 < MAX_STALE_RETRIES) {
194→                            debugLog("forward: StaleConnection during send (retry {d}/{d})", .{ stale_retries + 1, MAX_STALE_RETRIES });
195→                            // Note: connection is closed by errdefer in forwardWithConnection
196→                            continue; // Try next pooled connection
197→                        }
198→                        // Failed for real - end span with error and stale_retries count
199→                        self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
200→                        self.tracer.setIntAttribute(pool_span, "hit", 0);
201→                        self.tracer.endSpan(pool_span, @errorName(err));
202→                        return err;
203→                    };
204→
205→                    // SUCCESS - NOW record hit and end span
206→                    self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
207→                    self.tracer.setIntAttribute(pool_span, "hit", 1);
208→                    self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
209→                    self.tracer.endSpan(pool_span, null);
210→
211→                    self.tracer.endSpan(forward_span, null);
212→                    return result;
213→                } else {
214→                    break; // No more pooled connections, fall through to fresh
215→                }
216→            }
217→
218→            // Pool miss case - end span with hit=0
219→            const pool_end_ns = time.monotonicNanos();
220→            const pool_wait_ns = time.elapsedNanos(pool_start_ns, pool_end_ns);
221→            self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
222→            self.tracer.setIntAttribute(pool_span, "hit", 0);
223→            self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
224→            self.tracer.endSpan(pool_span, null);
225→
226→            // No pooled connection or all stale, create fresh
227→            debugLog("forward: pool MISS or exhausted stale, connecting fresh", .{});
228→            const result = try self.forwardFresh(io, client_stream, client_tls, request, upstream, body_info, pool_wait_ns, forward_span, effective_path);
229→            self.tracer.endSpan(forward_span, null);
230→            return result;
231→        }
232→
233→        /// Forward a WebSocket upgrade request and switch to tunnel mode on 101.
234→        /// Upgraded upstream connections are always closed, never returned to the pool.
235→        pub fn forwardWebSocket(
236→            self: *Self,
237→            io: Io,
238→            client_stream: Io.net.Stream,
239→            client_tls: ?*TLSStream,
240→            request: *const Request,
241→            upstream: *const Upstream,
242→            initial_client_bytes: []const u8,
243→            parent_span: SpanHandle,
244→            effective_path: ?[]const u8,
245→        ) ForwardError!ForwardResult {
246→            assert(upstream.port > 0);
247→            assert(request.path.len > 0);
248→            const request_key = request.headers.get("Sec-WebSocket-Key") orelse return ForwardError.InvalidResponse;
249→            const forwarded = ForwardedHeaders{
250→                .host = request.headers.get("Host") orelse "",
251→                .proto = if (client_tls != null) "https" else "http",
252→                .client_ip = "",
253→            };
254→
255→            var accept_key_buf: [serval_websocket.websocket_accept_key_size_bytes]u8 = undefined;
256→            const expected_accept = serval_websocket.computeAcceptKey(request_key, &accept_key_buf) catch {
257→                return ForwardError.InvalidResponse;
258→            };
259→
260→            debugLog("websocket forward start path={s} upstream={s}:{d} upstream_tls={any} protocol={s}", .{
261→                request.path,
262→                upstream.host,
263→                upstream.port,
264→                upstream.tls,
265→                @tagName(upstream.http_protocol),
266→            });
267→
268→            const forward_span = self.tracer.startSpan("forward_websocket_upgrade", parent_span);
269→            errdefer self.tracer.endSpan(forward_span, "forward_error");
270→
271→            const pool_span = self.tracer.startSpan("pool_acquire", forward_span);
272→            const pool_start_ns = time.monotonicNanos();
273→            var stale_retries: u8 = 0;
274→
275→            while (stale_retries < MAX_STALE_RETRIES) : (stale_retries += 1) {
276→                if (self.pool.acquire(upstream.idx)) |pooled_conn| {
277→                    const pool_wait_ns = time.elapsedNanos(pool_start_ns, time.monotonicNanos());
278→                    if (pooled_conn.isUnusable()) {
279→                        var stale_conn = pooled_conn;
280→                        stale_conn.close();
281→                        continue;
282→                    }
283→
284→                    const result = self.forwardWebSocketWithConnection(
285→                        io,
286→                        client_stream,
287→                        client_tls,
288→                        request,
289→                        upstream,
290→                        pooled_conn,
291→                        true,
292→                        initial_client_bytes,
293→                        expected_accept,
294→                        0,
295→                        0,
296→                        getLocalPortFromSocket(pooled_conn.socket),
297→                        pool_wait_ns,
298→                        forward_span,
299→                        effective_path,
300→                        forwarded,
301→                    ) catch |err| {
302→                        if (err == ForwardError.StaleConnection and stale_retries + 1 < MAX_STALE_RETRIES) {
303→                            continue;
304→                        }
305→                        self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
306→                        self.tracer.setIntAttribute(pool_span, "hit", 0);
307→                        self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
308→                        self.tracer.endSpan(pool_span, @errorName(err));
309→                        return err;
310→                    };
311→
312→                    self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
313→                    self.tracer.setIntAttribute(pool_span, "hit", 1);
314→                    self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
315→                    self.tracer.endSpan(pool_span, null);
316→                    self.tracer.endSpan(forward_span, null);
317→                    return result;
318→                }
319→                break;
320→            }
321→
322→            const pool_wait_ns = time.elapsedNanos(pool_start_ns, time.monotonicNanos());
323→            self.tracer.setIntAttribute(pool_span, "wait_ns", @intCast(pool_wait_ns));
324→            self.tracer.setIntAttribute(pool_span, "hit", 0);
325→            self.tracer.setIntAttribute(pool_span, "stale_retries", stale_retries);
326→            self.tracer.endSpan(pool_span, null);
327→
328→            const result = try self.forwardFreshWebSocket(
329→                io,
330→                client_stream,
331→                client_tls,
332→                request,
333→                upstream,
334→                initial_client_bytes,
335→                expected_accept,
336→                pool_wait_ns,
337→                forward_span,
338→                effective_path,
339→                forwarded,
340→            );
341→            self.tracer.endSpan(forward_span, null);
342→            return result;
343→        }
344→
345→        fn forwardFresh(
346→            self: *Self,
347→            io: Io,
348→            client_stream: Io.net.Stream,
349→            client_tls: ?*TLSStream,
350→            request: *const Request,
351→            upstream: *const Upstream,
352→            body_info: BodyInfo,
353→            pool_wait_ns: u64,
354→            forward_span: SpanHandle,
355→            effective_path: ?[]const u8,
356→        ) ForwardError!ForwardResult {
357→            assert(upstream.port > 0);
358→
359→            // TCP connect phase with span
360→            const connect_span = self.tracer.startSpan("tcp_connect", forward_span);
361→            const connect_config = ConnectConfig{
362→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
363→                .verify_upstream_tls = self.verify_upstream_tls,
364→                .client_ctx = self.client_ctx,
365→            };
366→            const connect_result = connectUpstream(upstream, io, connect_config, &self.dns_resolver) catch |err| {
367→                self.tracer.endSpan(connect_span, @errorName(err));
368→                return err;
369→            };
370→            self.tracer.setIntAttribute(connect_span, "duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
371→            self.tracer.setIntAttribute(connect_span, "port", connect_result.local_port);
372→            self.tracer.endSpan(connect_span, null);
373→
374→            // TLS handshake span (if TLS was used)
375→            // Access TLS stream info from Socket union if TLS variant.
376→            if (connect_result.socket.is_tls()) {
377→                const tls_socket = connect_result.socket.tls;
378→                const tls_span = self.tracer.startSpan("tls.handshake.client", forward_span);
379→                const info = &tls_socket.stream.info;
380→                self.tracer.setStringAttribute(tls_span, "tls.version", info.version());
381→                self.tracer.setStringAttribute(tls_span, "tls.cipher", info.cipher());
382→                self.tracer.setIntAttribute(tls_span, "tls.handshake_duration_ns", @intCast(info.handshake_duration_ns));
383→                self.tracer.setStringAttribute(tls_span, "tls.resumed", if (info.resumed) "true" else "false");
384→                self.tracer.setStringAttribute(tls_span, "tls.client_mode", "true");
385→                self.tracer.setStringAttribute(tls_span, "tls.sni_hostname", upstream.host);
386→                if (info.alpn()) |alpn_proto| {
387→                    self.tracer.setStringAttribute(tls_span, "tls.alpn_protocol", alpn_proto);
388→                }
389→                if (info.certSubject()) |subj| {
390→                    self.tracer.setStringAttribute(tls_span, "tls.peer_cert.subject", subj);
391→                }
392→                if (info.certIssuer()) |issuer| {
393→                    self.tracer.setStringAttribute(tls_span, "tls.peer_cert.issuer", issuer);
394→                }
395→                self.tracer.endSpan(tls_span, null);
396→            }
397→
398→            // Create Connection struct for pool compatibility
399→            // TigerStyle: Connection now uses Socket directly.
400→            const conn = Connection{
401→                .socket = connect_result.socket,
402→                .created_ns = connect_result.created_ns,
403→            };
404→
405→            return self.forwardWithConnection(
406→                io,
407→                client_stream,
408→                client_tls,
409→                request,
410→                upstream,
411→                conn,
412→                false,
413→                body_info,
414→                connect_result.dns_duration_ns,
415→                connect_result.tcp_connect_duration_ns,
416→                connect_result.local_port,
417→                pool_wait_ns,
418→                forward_span,
419→                effective_path,
420→            );
421→        }
422→
423→        fn forwardFreshWebSocket(
424→            self: *Self,
425→            io: Io,
426→            client_stream: Io.net.Stream,
427→            client_tls: ?*TLSStream,
428→            request: *const Request,
429→            upstream: *const Upstream,
430→            initial_client_bytes: []const u8,
431→            expected_accept: []const u8,
432→            pool_wait_ns: u64,
433→            forward_span: SpanHandle,
434→            effective_path: ?[]const u8,
435→            forwarded: ForwardedHeaders,
436→        ) ForwardError!ForwardResult {
437→            assert(upstream.port > 0);
438→
439→            const connect_span = self.tracer.startSpan("tcp_connect", forward_span);
440→            const connect_config = ConnectConfig{
441→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
442→                .verify_upstream_tls = self.verify_upstream_tls,
443→                .client_ctx = self.client_ctx,
444→            };
445→            const connect_result = connectUpstream(upstream, io, connect_config, &self.dns_resolver) catch |err| {
446→                self.tracer.endSpan(connect_span, @errorName(err));
447→                return err;
448→            };
449→            self.tracer.setIntAttribute(connect_span, "duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
450→            self.tracer.setIntAttribute(connect_span, "port", connect_result.local_port);
451→            self.tracer.endSpan(connect_span, null);
452→
453→            const conn = Connection{
454→                .socket = connect_result.socket,
455→                .created_ns = connect_result.created_ns,
456→            };
457→
458→            return self.forwardWebSocketWithConnection(
459→                io,
460→                client_stream,
461→                client_tls,
462→                request,
463→                upstream,
464→                conn,
465→                false,
466→                initial_client_bytes,
467→                expected_accept,
468→                connect_result.dns_duration_ns,
469→                connect_result.tcp_connect_duration_ns,
470→                connect_result.local_port,
471→                pool_wait_ns,
472→                forward_span,
473→                effective_path,
474→                forwarded,
475→            );
476→        }
477→
478→        fn forwardWebSocketWithConnection(
479→            self: *Self,
480→            io: Io,
481→            client_stream: Io.net.Stream,
482→            client_tls: ?*TLSStream,
483→            request: *const Request,
484→            upstream: *const Upstream,
485→            conn: Connection,
486→            is_pooled: bool,
487→            initial_client_bytes: []const u8,
488→            expected_accept: []const u8,
489→            dns_duration_ns: u64,
490→            tcp_connect_duration_ns: u64,
491→            local_port: u16,
492→            pool_wait_ns: u64,
493→            forward_span: SpanHandle,
494→            effective_path: ?[]const u8,
495→            forwarded: ForwardedHeaders,
496→        ) ForwardError!ForwardResult {
497→            var mutable_conn = conn;
498→            defer {
499→                if (is_pooled) {
500→                    self.pool.release(upstream.idx, mutable_conn, false);
501→                } else {
502→                    mutable_conn.close();
503→                }
504→            }
505→
506→            const send_span = self.tracer.startSpan("send_request", forward_span);
507→            const send_start_ns = time.monotonicNanos();
508→            sendUpgradeRequest(&mutable_conn, io, request, effective_path, forwarded) catch |err| {
509→                self.tracer.endSpan(send_span, @errorName(err));
510→                if (is_pooled and err == ForwardError.SendFailed) {
511→                    return ForwardError.StaleConnection;
512→                }
513→                return err;
514→            };
515→            const send_duration_ns = time.elapsedNanos(send_start_ns, time.monotonicNanos());
516→            self.tracer.setIntAttribute(send_span, "duration_ns", @intCast(send_duration_ns));
517→            self.tracer.endSpan(send_span, null);
518→
519→            var client_socket = if (client_tls) |tls|
520→                Socket{ .tls = .{ .fd = client_stream.socket.handle, .stream = tls.* } }
521→            else
522→                Socket.Plain.init_client(client_stream.socket.handle);
523→
524→            const recv_span = self.tracer.startSpan("recv_response", forward_span);
525→            const recv_start_ns = time.monotonicNanos();
526→            const upgrade_result = forwardUpgradeResponse(
527→                io,
528→                &mutable_conn,
529→                &client_socket,
530→                is_pooled,
531→                expected_accept,
532→            ) catch |err| {
533→                self.tracer.endSpan(recv_span, @errorName(err));
534→                return err;
535→            };
536→            const recv_duration_ns = time.elapsedNanos(recv_start_ns, time.monotonicNanos());
537→            self.tracer.setIntAttribute(recv_span, "duration_ns", @intCast(recv_duration_ns));
538→            self.tracer.setIntAttribute(recv_span, "status", upgrade_result.status);
539→            self.tracer.endSpan(recv_span, null);
540→
541→            debugLog("websocket upgrade response path={s} status={d} upgraded={any} reused={any} upstream={s}:{d}", .{
542→                request.path,
543→                upgrade_result.status,
544→                upgrade_result.upgraded,
545→                is_pooled,
546→                upstream.host,
547→                upstream.port,
548→            });
549→
550→            var result = ForwardResult{
551→                .status = upgrade_result.status,
552→                .response_bytes = upgrade_result.response_bytes,
553→                .connection_reused = is_pooled,
554→                .dns_duration_ns = dns_duration_ns,
555→                .tcp_connect_duration_ns = tcp_connect_duration_ns,
556→                .send_duration_ns = send_duration_ns,
557→                .recv_duration_ns = recv_duration_ns,
558→                .pool_wait_ns = pool_wait_ns,
559→                .upstream_local_port = local_port,
560→            };
561→
562→            if (!upgrade_result.upgraded) {
563→                return result;
564→            }
565→
566→            const tunnel_span = self.tracer.startSpan("websocket_tunnel", forward_span);
567→            const tunnel_stats = tunnel_mod.relay(
568→                io,
569→                &client_socket,
570→                &mutable_conn.socket,
571→                initial_client_bytes,
572→                &[_]u8{},
573→            );
574→            self.tracer.setIntAttribute(tunnel_span, "duration_ns", @intCast(tunnel_stats.duration_ns));
575→            self.tracer.setIntAttribute(tunnel_span, "client_to_upstream_bytes", @intCast(tunnel_stats.client_to_upstream_bytes));
576→            self.tracer.setIntAttribute(tunnel_span, "upstream_to_client_bytes", @intCast(tunnel_stats.upstream_to_client_bytes));
577→            self.tracer.setStringAttribute(tunnel_span, "termination", @tagName(tunnel_stats.termination));
578→            self.tracer.endSpan(tunnel_span, null);
579→
580→            debugLog("websocket tunnel complete termination={s} up_bytes={d} down_bytes={d}", .{
581→                @tagName(tunnel_stats.termination),
582→                tunnel_stats.client_to_upstream_bytes,
583→                tunnel_stats.upstream_to_client_bytes,
584→            });
585→
586→            result.response_bytes += tunnel_stats.upstream_to_client_bytes;
587→            result.recv_duration_ns += tunnel_stats.duration_ns;
588→            return result;
589→        }
590→
591→        /// Forward a gRPC HTTP/2 connection by selecting an upstream from the
592→        /// first request and then tunneling the full HTTP/2 byte stream
593→        /// transparently.
594→        ///
595→        /// Supported upstream protocol combinations:
596→        /// - `.h2c` + plaintext
597→        /// - `.h2` + TLS
598→        ///
599→        /// TigerStyle: Bounded upfront parsing happens in serval-server; this
600→        /// path performs raw relay only and never returns the upstream
601→        /// connection to the pool.
602→        pub fn forwardGrpcH2c(
603→            self: *Self,
604→            io: Io,
605→            client_stream: Io.net.Stream,
606→            client_tls: ?*TLSStream,
607→            request: *const Request,
608→            upstream: *const Upstream,
609→            initial_client_bytes: []const u8,
610→            parent_span: SpanHandle,
611→        ) ForwardError!ForwardResult {
612→            assert(initial_client_bytes.len > 0);
613→            assert(upstream.port > 0);
614→
615→            const supports_h2c_plain = upstream.http_protocol == .h2c and !upstream.tls;
616→            const supports_h2_tls = upstream.http_protocol == .h2 and upstream.tls;
617→            if (!supports_h2c_plain and !supports_h2_tls) return ForwardError.UnsupportedProtocol;
618→
619→            serval_grpc.validateRequest(request) catch return ForwardError.UnsupportedProtocol;
620→            _ = serval_h2.looksLikeClientConnectionPreface(initial_client_bytes);
621→
622→            const forward_span = self.tracer.startSpan("forward_grpc_h2", parent_span);
623→            errdefer self.tracer.endSpan(forward_span, "forward_error");
624→
625→            const connect_span = self.tracer.startSpan("connect_upstream", forward_span);
626→            const connect_cfg = ConnectConfig{
627→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
628→                .verify_upstream_tls = self.verify_upstream_tls,
629→                .client_ctx = self.client_ctx,
630→            };
631→            const connect_result = connectUpstream(
632→                upstream,
633→                io,
634→                connect_cfg,
635→                &self.dns_resolver,
636→            ) catch |err| {
637→                self.tracer.endSpan(connect_span, @errorName(err));
638→                return err;
639→            };
640→            self.tracer.setIntAttribute(connect_span, "dns_duration_ns", @intCast(connect_result.dns_duration_ns));
641→            self.tracer.setIntAttribute(connect_span, "tcp_connect_duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
642→            self.tracer.endSpan(connect_span, null);
643→
644→            var upstream_socket = connect_result.socket;
645→            defer upstream_socket.close();
646→            var client_socket = if (client_tls) |tls|
647→                Socket{ .tls = .{ .fd = client_stream.socket.handle, .stream = tls.* } }
648→            else
649→                Socket.Plain.init_client(client_stream.socket.handle);
650→
651→            const tunnel_span = self.tracer.startSpan("grpc_h2_tunnel", forward_span);
652→            const tunnel_stats = tunnel_mod.relayWithConfig(
653→                io,
654→                &client_socket,
655→                &upstream_socket,
656→                initial_client_bytes,
657→                &[_]u8{},
658→                config.H2C_TUNNEL_IDLE_TIMEOUT_NS,
659→                config.H2C_TUNNEL_POLL_TIMEOUT_MS,
660→            );
661→            self.tracer.setIntAttribute(tunnel_span, "duration_ns", @intCast(tunnel_stats.duration_ns));
662→            self.tracer.setIntAttribute(tunnel_span, "client_to_upstream_bytes", @intCast(tunnel_stats.client_to_upstream_bytes));
663→            self.tracer.setIntAttribute(tunnel_span, "upstream_to_client_bytes", @intCast(tunnel_stats.upstream_to_client_bytes));
664→            self.tracer.setStringAttribute(tunnel_span, "termination", @tagName(tunnel_stats.termination));
665→            self.tracer.endSpan(tunnel_span, null);
666→            self.tracer.endSpan(forward_span, null);
667→
668→            debugLog("grpc h2 tunnel complete termination={s} up_bytes={d} down_bytes={d}", .{
669→                @tagName(tunnel_stats.termination),
670→                tunnel_stats.client_to_upstream_bytes,
671→                tunnel_stats.upstream_to_client_bytes,
672→            });
673→
674→            return .{
675→                .status = 200,
676→                .response_bytes = tunnel_stats.upstream_to_client_bytes,
677→                .connection_reused = false,
678→                .dns_duration_ns = connect_result.dns_duration_ns,
679→                .tcp_connect_duration_ns = connect_result.tcp_connect_duration_ns,
680→                .send_duration_ns = 0,
681→                .recv_duration_ns = tunnel_stats.duration_ns,
682→                .pool_wait_ns = 0,
683→                .upstream_local_port = connect_result.local_port,
684→            };
685→        }
686→
687→        const H2C_UPGRADE_STREAM_ID: u32 = 1;
688→        const H2C_UPGRADE_PREAMBLE_BUFFER_SIZE_BYTES: usize =
689→            serval_h2.client_connection_preface.len +
690→            (2 * serval_h2.frame_header_size_bytes) +
691→            config.H2_MAX_FRAME_SIZE_BYTES +
692→            config.H2_MAX_HEADER_BLOCK_SIZE_BYTES;
693→
694→        /// Forward an HTTP/1.1 `Upgrade: h2c` gRPC request by translating the
695→        /// upgrade exchange into an upstream prior-knowledge h2c session.
696→        /// After the initial request is translated, all further HTTP/2 bytes are
697→        /// tunneled transparently end-to-end.
698→        pub fn forwardGrpcH2cUpgrade(
699→            self: *Self,
700→            io: Io,
701→            client_stream: Io.net.Stream,
702→            client_tls: ?*TLSStream,
703→            request: *const Request,
704→            upstream: *const Upstream,
705→            body_info: BodyInfo,
706→            initial_client_bytes_after_body: []const u8,
707→            decoded_settings_payload: []const u8,
708→            parent_span: SpanHandle,
709→            effective_path: ?[]const u8,
710→        ) ForwardError!ForwardResult {
711→            assert(upstream.port > 0);
712→            assert(decoded_settings_payload.len <= config.H2_MAX_FRAME_SIZE_BYTES);
713→
714→            if (client_tls != null) return ForwardError.UnsupportedProtocol;
715→            if (upstream.http_protocol != .h2c) return ForwardError.UnsupportedProtocol;
716→            if (upstream.tls) return ForwardError.UnsupportedProtocol;
717→            if (body_info.framing == .chunked) return ForwardError.UnsupportedProtocol;
718→            serval_grpc.validateRequest(request) catch return ForwardError.UnsupportedProtocol;
719→
720→            const forward_span = self.tracer.startSpan("forward_grpc_h2c_upgrade", parent_span);
721→            errdefer self.tracer.endSpan(forward_span, "forward_error");
722→
723→            const connect_span = self.tracer.startSpan("connect_upstream", forward_span);
724→            const connect_cfg = ConnectConfig{
725→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
726→                .verify_upstream_tls = self.verify_upstream_tls,
727→                .client_ctx = self.client_ctx,
728→            };
729→            const connect_result = connectUpstream(
730→                upstream,
731→                io,
732→                connect_cfg,
733→                &self.dns_resolver,
734→            ) catch |err| {
735→                self.tracer.endSpan(connect_span, @errorName(err));
736→                return err;
737→            };
738→            self.tracer.setIntAttribute(connect_span, "dns_duration_ns", @intCast(connect_result.dns_duration_ns));
739→            self.tracer.setIntAttribute(connect_span, "tcp_connect_duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
740→            self.tracer.endSpan(connect_span, null);
741→
742→            var upstream_socket = connect_result.socket;
743→            defer upstream_socket.close();
744→            var client_socket = Socket.Plain.init_client(client_stream.socket.handle);
745→
746→            const content_length = body_info.getContentLength() orelse 0;
747→            assert(body_info.bytes_already_read <= content_length);
748→            const remaining_body_bytes = content_length - body_info.bytes_already_read;
749→            const has_request_body = content_length > 0;
750→
751→            var preamble_buf: [H2C_UPGRADE_PREAMBLE_BUFFER_SIZE_BYTES]u8 = undefined;
752→            const preamble = serval_h2.buildPriorKnowledgePreambleFromUpgrade(
753→                &preamble_buf,
754→                request,
755→                effective_path,
756→                decoded_settings_payload,
757→                !has_request_body,
758→            ) catch return ForwardError.UnsupportedProtocol;
759→            upstream_socket.write_all(preamble) catch return ForwardError.SendFailed;
760→
761→            if (body_info.initial_body.len > 0) {
762→                sendH2DataFrames(
763→                    &upstream_socket,
764→                    body_info.initial_body,
765→                    remaining_body_bytes == 0,
766→                ) catch return ForwardError.SendFailed;
767→            }
768→
769→            client_socket.write_all(serval_h2.h2c_upgrade_response) catch return ForwardError.SendFailed;
770→
771→            const tunnel_span = self.tracer.startSpan("grpc_h2c_upgrade_tunnel", forward_span);
772→            const tunnel_stats = relayGrpcH2cUpgradeSession(
773→                io,
774→                &client_socket,
775→                &upstream_socket,
776→                remaining_body_bytes,
777→                initial_client_bytes_after_body,
778→            );
779→            self.tracer.setIntAttribute(tunnel_span, "duration_ns", @intCast(tunnel_stats.duration_ns));
780→            self.tracer.setIntAttribute(tunnel_span, "client_to_upstream_bytes", @intCast(tunnel_stats.client_to_upstream_bytes));
781→            self.tracer.setIntAttribute(tunnel_span, "upstream_to_client_bytes", @intCast(tunnel_stats.upstream_to_client_bytes));
782→            self.tracer.setStringAttribute(tunnel_span, "termination", @tagName(tunnel_stats.termination));
783→            self.tracer.endSpan(tunnel_span, null);
784→            self.tracer.endSpan(forward_span, null);
785→
786→            debugLog("grpc h2c upgrade tunnel complete termination={s} up_bytes={d} down_bytes={d}", .{
787→                @tagName(tunnel_stats.termination),
788→                tunnel_stats.client_to_upstream_bytes,
789→                tunnel_stats.upstream_to_client_bytes,
790→            });
791→
792→            return .{
793→                .status = 101,
794→                .response_bytes = serval_h2.h2c_upgrade_response.len + tunnel_stats.upstream_to_client_bytes,
795→                .connection_reused = false,
796→                .dns_duration_ns = connect_result.dns_duration_ns,
797→                .tcp_connect_duration_ns = connect_result.tcp_connect_duration_ns,
798→                .send_duration_ns = 0,
799→                .recv_duration_ns = tunnel_stats.duration_ns,
800→                .pool_wait_ns = 0,
801→                .upstream_local_port = connect_result.local_port,
802→            };
803→        }
804→
805→        fn relayGrpcH2cUpgradeSession(
806→            io: Io,
807→            client_socket: *Socket,
808→            upstream_socket: *Socket,
809→            remaining_body_bytes: u64,
810→            initial_client_bytes_after_body: []const u8,
811→        ) tunnel_mod.TunnelStats {
812→            const start_ns = time.monotonicNanos();
813→            var stats = tunnel_mod.TunnelStats{};
814→
815→            if (remaining_body_bytes > 0) {
816→                if (streamGrpcH2cUpgradeBody(client_socket, upstream_socket, remaining_body_bytes, &stats.client_to_upstream_bytes)) |termination| {
817→                    stats.duration_ns = @intCast(time.elapsedNanos(start_ns, time.monotonicNanos()));
818→                    stats.termination = termination;
819→                    return stats;
820→                }
821→            }
822→
823→            const tunnel_stats = tunnel_mod.relayWithConfig(
824→                io,
825→                client_socket,
826→                upstream_socket,
827→                initial_client_bytes_after_body,
828→                &[_]u8{},
829→                config.H2C_TUNNEL_IDLE_TIMEOUT_NS,
830→                config.H2C_TUNNEL_POLL_TIMEOUT_MS,
831→            );
832→            stats.client_to_upstream_bytes += tunnel_stats.client_to_upstream_bytes;
833→            stats.upstream_to_client_bytes += tunnel_stats.upstream_to_client_bytes;
834→            stats.duration_ns = @intCast(time.elapsedNanos(start_ns, time.monotonicNanos()));
835→            stats.termination = tunnel_stats.termination;
836→            return stats;
837→        }
838→
839→        fn streamGrpcH2cUpgradeBody(
840→            client_socket: *Socket,
841→            upstream_socket: *Socket,
842→            remaining_body_bytes: u64,
843→            counter_bytes: *u64,
844→        ) ?tunnel_mod.Termination {
845→            assert(remaining_body_bytes > 0);
846→
847→            var body_buf: [config.H2_MAX_FRAME_SIZE_BYTES]u8 = undefined;
848→            var remaining = remaining_body_bytes;
849→
850→            while (remaining > 0) {
851→                const to_read: usize = @intCast(@min(remaining, config.H2_MAX_FRAME_SIZE_BYTES));
852→                const bytes_read = client_socket.read(body_buf[0..to_read]) catch |err| {
853→                    return mapClientReadTermination(err);
854→                };
855→                if (bytes_read == 0) return .client_closed;
856→
857→                const end_stream = remaining == bytes_read;
858→                sendH2DataFrames(upstream_socket, body_buf[0..bytes_read], end_stream) catch |err| {
859→                    return mapUpstreamWriteTermination(err);
860→                };
861→                counter_bytes.* += bytes_read;
862→                remaining -= bytes_read;
863→            }
864→
865→            return null;
866→        }
867→
868→        fn sendH2DataFrames(
869→            upstream_socket: *Socket,
870→            payload: []const u8,
871→            end_stream: bool,
872→        ) serval_socket.SocketError!void {
873→            if (payload.len == 0) {
874→                if (end_stream) try sendH2Frame(upstream_socket, .data, serval_h2.flags_end_stream, H2C_UPGRADE_STREAM_ID, &[_]u8{});
875→                return;
876→            }
877→
878→            var cursor: usize = 0;
879→            while (cursor < payload.len) {
880→                const remaining = payload.len - cursor;
881→                const chunk_len: usize = @intCast(@min(remaining, config.H2_MAX_FRAME_SIZE_BYTES));
882→                const chunk = payload[cursor .. cursor + chunk_len];
883→                const is_last_chunk = cursor + chunk_len == payload.len;
884→                const flags: u8 = if (end_stream and is_last_chunk) serval_h2.flags_end_stream else 0;
885→                try sendH2Frame(upstream_socket, .data, flags, H2C_UPGRADE_STREAM_ID, chunk);
886→                cursor += chunk_len;
887→            }
888→        }
889→
890→        fn sendH2Frame(
891→            upstream_socket: *Socket,
892→            frame_type: serval_h2.FrameType,
893→            flags: u8,
894→            stream_id: u32,
895→            payload: []const u8,
896→        ) serval_socket.SocketError!void {
897→            var header_buf: [serval_h2.frame_header_size_bytes]u8 = undefined;
898→            const header = serval_h2.buildFrameHeader(&header_buf, .{
899→                .length = @intCast(payload.len),
900→                .frame_type = frame_type,

  1→//! Stream-Aware HTTP/2 Proxy Bridge
  2→//!
  3→//! Bounded downstream↔upstream stream mapping helpers that use
  4→//! `serval-client` outbound h2 sessions.
  5→//!
  6→//! This is an initial Phase D bridge: it does not own downstream sockets yet.
  7→//! It opens upstream streams, binds stream ids, forwards DATA for bound streams,
  8→//! and maps upstream receive actions back to downstream stream ids.
  9→//! TigerStyle: Fixed-capacity tables, explicit errors, no allocation.
 10→
 11→const std = @import("std");
 12→const Io = std.Io;
 13→const assert = std.debug.assert;
 14→
 15→const core = @import("serval-core");
 16→const config = core.config;
 17→const types = core.types;
 18→const log = core.log.scoped(.proxy);
 19→
 20→const h2 = @import("serval-h2");
 21→const serval_client = @import("serval-client");
 22→const bindings = @import("bindings.zig");
 23→
 24→const Upstream = types.Upstream;
 25→const Request = types.Request;
 26→const Response = types.Response;
 27→const HeaderMap = types.HeaderMap;
 28→
 29→pub const Error = error{
 30→    SessionNotFound,
 31→    UnexpectedReceiveAction,
 32→} || bindings.Error || serval_client.H2UpstreamSessionError;
 33→
 34→pub const OpenResult = struct {
 35→    binding: bindings.Binding,
 36→    connect: serval_client.H2UpstreamConnectStats,
 37→};
 38→
 39→pub const ResponseHeadersAction = struct {
 40→    downstream_stream_id: u32,
 41→    end_stream: bool,
 42→    response: Response,
 43→};
 44→
 45→pub const ResponseDataAction = struct {
 46→    downstream_stream_id: u32,
 47→    end_stream: bool,
 48→    payload: []const u8,
 49→};
 50→
 51→pub const ResponseTrailersAction = struct {
 52→    downstream_stream_id: u32,
 53→    trailers: HeaderMap,
 54→};
 55→
 56→pub const StreamResetAction = struct {
 57→    downstream_stream_id: u32,
 58→    error_code_raw: u32,
 59→};
 60→
 61→pub const ConnectionCloseAction = struct {
 62→    upstream_index: config.UpstreamIndex,
 63→    upstream_session_generation: u32,
 64→    goaway: h2.GoAway,
 65→};
 66→
 67→pub const ReceiveAction = union(enum) {
 68→    none,
 69→    response_headers: ResponseHeadersAction,
 70→    response_data: ResponseDataAction,
 71→    response_trailers: ResponseTrailersAction,
 72→    stream_reset: StreamResetAction,
 73→    connection_close: ConnectionCloseAction,
 74→};
 75→
 76→pub const StreamBridge = struct {
 77→    client: *serval_client.Client,
 78→    sessions: *serval_client.H2UpstreamSessionPool,
 79→    binding_table: bindings.BindingTable = bindings.BindingTable.init(),
 80→
 81→    pub fn init(client: *serval_client.Client, sessions: *serval_client.H2UpstreamSessionPool) StreamBridge {
 82→        assert(@intFromPtr(client) != 0);
 83→        assert(@intFromPtr(sessions) != 0);
 84→
 85→        return .{
 86→            .client = client,
 87→            .sessions = sessions,
 88→        };
 89→    }
 90→
 91→    pub fn deinit(self: *StreamBridge) void {
 92→        assert(@intFromPtr(self) != 0);
 93→
 94→        self.binding_table = bindings.BindingTable.init();
 95→        self.sessions.closeAll();
 96→    }
 97→
 98→    pub fn openDownstreamStream(
 99→        self: *StreamBridge,
100→        io: Io,
101→        upstream: Upstream,
102→        downstream_stream_id: u32,
103→        request: *const Request,
104→        effective_path: ?[]const u8,
105→        end_stream: bool,
106→    ) Error!OpenResult {
107→        assert(@intFromPtr(self) != 0);
108→        assert(downstream_stream_id > 0);
109→        assert(upstream.port > 0);
110→        assert(request.path.len > 0);
111→
112→        if (self.binding_table.getByDownstream(downstream_stream_id) != null) {
113→            return error.DuplicateDownstreamStream;
114→        }
115→
116→        const max_open_attempts: u8 = config.H2_MAX_SESSIONS_PER_UPSTREAM;
117→        var attempts: u8 = 0;
118→
119→        while (attempts < max_open_attempts) : (attempts += 1) {
120→            const acquired = try self.sessions.acquireOrConnect(self.client, upstream, io);
121→            const upstream_stream_id = acquired.session.sendRequestHeaders(request, effective_path, end_stream) catch |err| switch (err) {
122→                error.ConnectionClosing => {
123→                    self.sessions.closeGeneration(upstream.idx, acquired.session.generation);
124→                    if (attempts + 1 >= max_open_attempts) return err;
125→                    continue;
126→                },
127→                else => return err,
128→            };
129→
130→            const binding = bindings.Binding{
131→                .downstream_stream_id = downstream_stream_id,
132→                .upstream_stream_id = upstream_stream_id,
133→                .upstream_index = upstream.idx,
134→                .upstream_session_generation = acquired.session.generation,
135→            };
136→            try self.binding_table.put(binding);
137→
138→            return .{
139→                .binding = binding,
140→                .connect = acquired.connect,
141→            };
142→        }
143→
144→        return error.ConnectionClosing;
145→    }
146→
147→    pub fn sendDownstreamData(
148→        self: *StreamBridge,
149→        downstream_stream_id: u32,
150→        payload: []const u8,
151→        end_stream: bool,
152→    ) Error!void {
153→        assert(@intFromPtr(self) != 0);
154→        assert(downstream_stream_id > 0);
155→
156→        const binding = self.binding_table.getByDownstream(downstream_stream_id) orelse return error.BindingNotFound;
157→        const session = self.sessions.getByGeneration(binding.upstream_index, binding.upstream_session_generation) orelse return error.SessionNotFound;
158→
159→        session.sendRequestData(binding.upstream_stream_id, payload, end_stream) catch |err| switch (err) {
160→            error.ConnectionClosed => {
161→                if (!end_stream) return err;
162→
163→                log.warn(
164→                    "h2 bridge: downstream={d} upstream={d} idx={d} gen={d} final sendRequestData saw ConnectionClosed; preserving binding for in-flight response",
165→                    .{
166→                        downstream_stream_id,
167→                        binding.upstream_stream_id,
168→                        binding.upstream_index,
169→                        binding.upstream_session_generation,
170→                    },
171→                );
172→                return;
173→            },
174→            error.ConnectionClosing => {
175→                if (end_stream) {
176→                    log.warn(
177→                        "h2 bridge: downstream={d} upstream={d} idx={d} gen={d} final sendRequestData saw ConnectionClosing; goaway_received={any} last_stream_id={d} preserving binding",
178→                        .{
179→                            downstream_stream_id,
180→                            binding.upstream_stream_id,
181→                            binding.upstream_index,
182→                            binding.upstream_session_generation,
183→                            session.h2.runtime.state.goaway_received,
184→                            session.h2.runtime.state.peer_goaway_last_stream_id,
185→                        },
186→                    );
187→                    return;
188→                }
189→
190→                log.warn(
191→                    "h2 bridge: downstream={d} upstream={d} idx={d} gen={d} sendRequestData failed with ConnectionClosing; goaway_received={any} last_stream_id={d} failing closed",
192→                    .{
193→                        downstream_stream_id,
194→                        binding.upstream_stream_id,
195→                        binding.upstream_index,
196→                        binding.upstream_session_generation,
197→                        session.h2.runtime.state.goaway_received,
198→                        session.h2.runtime.state.peer_goaway_last_stream_id,
199→                    },
200→                );
201→
202→                _ = self.binding_table.removeByDownstream(downstream_stream_id) catch |remove_err| switch (remove_err) {
203→                    error.BindingNotFound => return err,
204→                    else => return remove_err,
205→                };
206→                self.sessions.closeGeneration(binding.upstream_index, binding.upstream_session_generation);
207→                return err;
208→            },
209→            else => return err,
210→        };
211→    }
212→
213→    pub fn bindingForDownstream(self: *const StreamBridge, downstream_stream_id: u32) ?bindings.Binding {
214→        assert(@intFromPtr(self) != 0);
215→        assert(downstream_stream_id > 0);
216→
217→        return self.binding_table.getByDownstream(downstream_stream_id);
218→    }
219→
220→    pub fn cancelDownstreamStream(
221→        self: *StreamBridge,
222→        downstream_stream_id: u32,
223→        error_code_raw: u32,
224→    ) Error!void {
225→        assert(@intFromPtr(self) != 0);
226→        assert(downstream_stream_id > 0);
227→
228→        const binding = self.binding_table.removeByDownstream(downstream_stream_id) catch |err| switch (err) {
229→            error.BindingNotFound => return,
230→            else => return err,
231→        };
232→
233→        const session = self.sessions.getByGeneration(binding.upstream_index, binding.upstream_session_generation) orelse return error.SessionNotFound;
234→        session.sendStreamReset(binding.upstream_stream_id, error_code_raw) catch |err| switch (err) {
235→            error.StreamNotFound => {},
236→            else => return err,
237→        };
238→    }
239→
240→    pub fn receiveForUpstream(
241→        self: *StreamBridge,
242→        upstream_index: config.UpstreamIndex,
243→    ) Error!ReceiveAction {
244→        assert(@intFromPtr(self) != 0);
245→
246→        const session = self.sessions.get(upstream_index) orelse return error.SessionNotFound;
247→        const action = try session.receiveActionHandlingControl();
248→        return self.mapReceiveAction(upstream_index, session.generation, action);
249→    }
250→
251→    pub fn receiveForDownstream(
252→        self: *StreamBridge,
253→        io: Io,
254→        timeout: Io.Timeout,
255→        downstream_stream_id: u32,
256→    ) Error!ReceiveAction {
257→        assert(@intFromPtr(self) != 0);
258→        assert(downstream_stream_id > 0);
259→
260→        const binding = self.binding_table.getByDownstream(downstream_stream_id) orelse return error.BindingNotFound;
261→        const session = self.sessions.getByGeneration(binding.upstream_index, binding.upstream_session_generation) orelse return error.SessionNotFound;
262→
263→        const action = try session.receiveActionHandlingControlTimeout(io, timeout);
264→        return self.mapReceiveAction(binding.upstream_index, binding.upstream_session_generation, action);
265→    }
266→
267→    pub fn closeUpstream(self: *StreamBridge, upstream_index: config.UpstreamIndex) void {
268→        assert(@intFromPtr(self) != 0);
269→
270→        _ = self.binding_table.removeAllForUpstream(upstream_index);
271→        self.sessions.close(upstream_index);
272→    }
273→
274→    pub fn activeBindingCount(self: *const StreamBridge) u16 {
275→        assert(@intFromPtr(self) != 0);
276→        return self.binding_table.count;
277→    }
278→
279→    fn mapReceiveAction(
280→        self: *StreamBridge,
281→        upstream_index: config.UpstreamIndex,
282→        upstream_session_generation: u32,
283→        action: serval_client.H2ReceiveAction,
284→    ) Error!ReceiveAction {
285→        assert(@intFromPtr(self) != 0);
286→
287→        return switch (action) {
288→            .none => .none,
289→            .response_headers => |response_headers| {
290→                const binding = self.binding_table.getByUpstreamForSession(upstream_index, upstream_session_generation, response_headers.stream_id) orelse return error.BindingNotFound;
291→                if (response_headers.end_stream) {
292→                    _ = try self.binding_table.removeByDownstream(binding.downstream_stream_id);
293→                }
294→                return .{ .response_headers = .{
295→                    .downstream_stream_id = binding.downstream_stream_id,
296→                    .end_stream = response_headers.end_stream,
297→                    .response = response_headers.response,
298→                } };
299→            },
300→            .response_data => |response_data| {
301→                const binding = self.binding_table.getByUpstreamForSession(upstream_index, upstream_session_generation, response_data.stream_id) orelse return error.BindingNotFound;
302→                if (response_data.end_stream) {
303→                    _ = try self.binding_table.removeByDownstream(binding.downstream_stream_id);
304→                }
305→                return .{ .response_data = .{
306→                    .downstream_stream_id = binding.downstream_stream_id,
307→                    .end_stream = response_data.end_stream,
308→                    .payload = response_data.payload,
309→                } };
310→            },
311→            .response_trailers => |response_trailers| {
312→                const binding = self.binding_table.getByUpstreamForSession(upstream_index, upstream_session_generation, response_trailers.stream_id) orelse return error.BindingNotFound;
313→                _ = try self.binding_table.removeByDownstream(binding.downstream_stream_id);
314→                return .{ .response_trailers = .{
315→                    .downstream_stream_id = binding.downstream_stream_id,
316→                    .trailers = response_trailers.trailers,
317→                } };
318→            },
319→            .stream_reset => |stream_reset| {
320→                const binding = self.binding_table.getByUpstreamForSession(upstream_index, upstream_session_generation, stream_reset.stream_id) orelse return error.BindingNotFound;
321→                _ = try self.binding_table.removeByDownstream(binding.downstream_stream_id);
322→                return .{ .stream_reset = .{
323→                    .downstream_stream_id = binding.downstream_stream_id,
324→                    .error_code_raw = stream_reset.error_code_raw,
325→                } };
326→            },
327→            .connection_close => |goaway| {
328→                if (goaway.error_code_raw != @intFromEnum(h2.ErrorCode.no_error)) {
329→                    _ = self.binding_table.removeAllForUpstreamSession(upstream_index, upstream_session_generation);
330→                    self.sessions.closeGeneration(upstream_index, upstream_session_generation);
331→                }
332→                return .{ .connection_close = .{
333→                    .upstream_index = upstream_index,
334→                    .upstream_session_generation = upstream_session_generation,
335→                    .goaway = goaway,
336→                } };
337→            },
338→            else => return error.UnexpectedReceiveAction,
339→        };
340→    }
341→};
