590→
591→        /// Forward a gRPC HTTP/2 connection by selecting an upstream from the
592→        /// first request and then tunneling the full HTTP/2 byte stream
593→        /// transparently.
594→        ///
595→        /// Supported upstream protocol combinations:
596→        /// - `.h2c` + plaintext
597→        /// - `.h2` + TLS
598→        ///
599→        /// TigerStyle: Bounded upfront parsing happens in serval-server; this
600→        /// path performs raw relay only and never returns the upstream
601→        /// connection to the pool.
602→        pub fn forwardGrpcH2c(
603→            self: *Self,
604→            io: Io,
605→            client_stream: Io.net.Stream,
606→            client_tls: ?*TLSStream,
607→            request: *const Request,
608→            upstream: *const Upstream,
609→            initial_client_bytes: []const u8,
610→            parent_span: SpanHandle,
611→        ) ForwardError!ForwardResult {
612→            assert(initial_client_bytes.len > 0);
613→            assert(upstream.port > 0);
614→
615→            const supports_h2c_plain = upstream.http_protocol == .h2c and !upstream.tls;
616→            const supports_h2_tls = upstream.http_protocol == .h2 and upstream.tls;
617→            if (!supports_h2c_plain and !supports_h2_tls) return ForwardError.UnsupportedProtocol;
618→
619→            serval_grpc.validateRequest(request) catch return ForwardError.UnsupportedProtocol;
620→            _ = serval_h2.looksLikeClientConnectionPreface(initial_client_bytes);
621→
622→            const forward_span = self.tracer.startSpan("forward_grpc_h2", parent_span);
623→            errdefer self.tracer.endSpan(forward_span, "forward_error");
624→
625→            const connect_span = self.tracer.startSpan("connect_upstream", forward_span);
626→            const connect_cfg = ConnectConfig{
627→                .timeout_ns = config.CONNECT_TIMEOUT_NS,
628→                .verify_upstream_tls = self.verify_upstream_tls,
629→                .client_ctx = self.client_ctx,
630→            };
631→            const connect_result = connectUpstream(
632→                upstream,
633→                io,
634→                connect_cfg,
635→                &self.dns_resolver,
636→            ) catch |err| {
637→                self.tracer.endSpan(connect_span, @errorName(err));
638→                return err;
639→            };
640→            self.tracer.setIntAttribute(connect_span, "dns_duration_ns", @intCast(connect_result.dns_duration_ns));
641→            self.tracer.setIntAttribute(connect_span, "tcp_connect_duration_ns", @intCast(connect_result.tcp_connect_duration_ns));
642→            self.tracer.endSpan(connect_span, null);
643→
644→            var upstream_socket = connect_result.socket;
645→            defer upstream_socket.close();
646→            var client_socket = if (client_tls) |tls|
647→                Socket{ .tls = .{ .fd = client_stream.socket.handle, .stream = tls.* } }
648→            else
649→                Socket.Plain.init_client(client_stream.socket.handle);
650→
651→            const tunnel_span = self.tracer.startSpan("grpc_h2_tunnel", forward_span);
652→            const tunnel_stats = tunnel_mod.relayWithConfig(
653→                io,
654→                &client_socket,
655→                &upstream_socket,
656→                initial_client_bytes,
657→                &[_]u8{},
658→                config.H2C_TUNNEL_IDLE_TIMEOUT_NS,
659→                config.H2C_TUNNEL_POLL_TIMEOUT_MS,
660→            );
661→            self.tracer.setIntAttribute(tunnel_span, "duration_ns", @intCast(tunnel_stats.duration_ns));
662→            self.tracer.setIntAttribute(tunnel_span, "client_to_upstream_bytes", @intCast(tunnel_stats.client_to_upstream_bytes));
663→            self.tracer.setIntAttribute(tunnel_span, "upstream_to_client_bytes", @intCast(tunnel_stats.upstream_to_client_bytes));
664→            self.tracer.setStringAttribute(tunnel_span, "termination", @tagName(tunnel_stats.termination));
665→            self.tracer.endSpan(tunnel_span, null);
666→            self.tracer.endSpan(forward_span, null);
667→
668→            debugLog("grpc h2 tunnel complete termination={s} up_bytes={d} down_bytes={d}", .{
